const raw = items[0].json.output;
const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;

return [{
  json: {
    output: parsed.reply || '',
    handover: Boolean(parsed.handover),
    handoverReason: parsed.handoverReason || (parsed.handover ? 'Harold requested human assistance.' : null),
  },
}];
